"""sklearn.kernel_ridge — Kernel Ridge Regression."""
import numpy as np
from sklearn.base import BaseEstimator, RegressorMixin


class KernelRidge(BaseEstimator, RegressorMixin):
    """Kernel Ridge Regression.

    Parameters
    ----------
    alpha : float, default=1.0
    kernel : str, default='rbf'
    gamma : float, default=1.0
    """

    def __init__(self, alpha=1.0, kernel='rbf', gamma=1.0):
        self.alpha = alpha
        self.kernel = kernel
        self.gamma = gamma

    def _kernel_func(self, X, Y):
        if self.kernel == 'linear':
            return X @ Y.T
        # RBF
        sq_dist = np.sum(X ** 2, axis=1, keepdims=True) + \
                  np.sum(Y ** 2, axis=1) - 2 * X @ Y.T
        return np.exp(-self.gamma * sq_dist)

    def fit(self, X, y):
        self.X_fit_ = np.asarray(X, dtype=float)
        y = np.asarray(y, dtype=float)
        K = self._kernel_func(self.X_fit_, self.X_fit_)
        K += self.alpha * np.eye(K.shape[0])
        self.dual_coef_ = np.linalg.solve(K, y)
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        K = self._kernel_func(X, self.X_fit_)
        return K @ self.dual_coef_
